import{_ as e,o as d,c as r,a0 as a}from"./chunks/framework.B3sz4m_N.js";const o=""+new URL("../report/agentic-techniques-02-technique-inventory.png",import.meta.url).href,g=JSON.parse('{"title":"Technique Inventory","description":"Full catalogue of agentic engineering techniques from all nine chapters, assessed against the Dark Factory workflow.","frontmatter":{"title":"Technique Inventory","description":"Full catalogue of agentic engineering techniques from all nine chapters, assessed against the Dark Factory workflow."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/02-technique-inventory.md","filePath":"reports/agentic-engineering-techniques/02-technique-inventory.md"}'),i={name:"reports/agentic-engineering-techniques/02-technique-inventory.md"};function n(s,t,l,h,c,p){return d(),r("div",null,[...t[0]||(t[0]=[a('<figure class="report-section-image-wrapper" aria-labelledby="fig-inventory-caption"><img src="'+o+'" alt="A naturalist&#39;s specimen drawer with labelled compartments, each containing a different mechanical part" loading="lazy" class="report-section-image"><figcaption id="fig-inventory-caption">Cataloguing the full spectrum of agentic engineering techniques</figcaption></figure><h2 id="_2-technique-inventory" tabindex="-1">2. Technique Inventory <a class="header-anchor" href="#_2-technique-inventory" aria-label="Permalink to &quot;2. Technique Inventory&quot;">​</a></h2><p>Every distinct technique from the <a href="https://jayminwest.com/agentic-engineering-book" target="_blank" rel="noreferrer">Agentic Engineering Book</a> is catalogued below, organised by chapter. Each is assessed for relevance to the Dark Factory workflow and current adoption status.</p><h3 id="chapter-1-foundations" tabindex="-1">Chapter 1: Foundations <a class="header-anchor" href="#chapter-1-foundations" aria-label="Permalink to &quot;Chapter 1: Foundations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Four-pillar decomposition</td><td>Prompt + Model + Context + Tool Use as independent concerns</td><td>High</td><td>Implicit, not explicit</td></tr><tr><td>&quot;More is not better&quot; principle</td><td>Focused agents outperform overloaded ones</td><td>High</td><td>Partially applied</td></tr><tr><td>Pit of Success mindset</td><td>Design so the easiest path is the correct path</td><td>High</td><td>Not applied</td></tr><tr><td>Common mistakes checklist</td><td>8 anti-patterns for new practitioners</td><td>Medium</td><td>Not documented</td></tr></tbody></table><p><strong>Key insight:</strong> &quot;A focused agent is a productive agent.&quot; The book warns against flooding agents with tools, context, and steering prompts — each addition degrades performance. The workflow&#39;s single-purpose skills align with this, but the one-shot runner (which loads everything into one context) works against it.</p><h3 id="chapter-2-prompt" tabindex="-1">Chapter 2: Prompt <a class="header-anchor" href="#chapter-2-prompt" aria-label="Permalink to &quot;Chapter 2: Prompt&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Distributed prompt architecture</td><td>Prompt spans skills, rules, injected context</td><td>High</td><td>Partial — no composition map</td></tr><tr><td>Static-to-composed prompt spectrum</td><td>5-level maturity for prompt dynamism</td><td>Medium</td><td>Skills are Level 4 (Contextual)</td></tr><tr><td>Prompt-model contract</td><td>Explicit model capability assumptions</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Clarity over cleverness</td><td>Explicit instructions outperform clever shortcuts</td><td>High</td><td><strong>Strong</strong></td></tr><tr><td>Structure reduces variance</td><td>Consistent formatting helps models parse intent</td><td>High</td><td><strong>Strong</strong></td></tr><tr><td>Constraints enable creativity</td><td>Scope boundaries improve output quality</td><td>High</td><td><strong>Strong</strong></td></tr><tr><td>Examples beat explanations</td><td>Few-shot examples establish format and tone</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Tool docs with negative constraints</td><td>&quot;Do NOT use for&quot; prevents skill misuse</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Stopping conditions</td><td>Explicit criteria for when agents halt</td><td>High</td><td>Partial</td></tr><tr><td>Uncertainty handling</td><td>When to ask the user vs proceed with best judgment</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Model-invoked vs user-invoked design</td><td>Rich descriptions with trigger terms and scope boundaries</td><td>High</td><td>Partial</td></tr><tr><td>Prompt quality measurement</td><td>Multi-dimensional scoring of prompt effectiveness</td><td>Medium</td><td>Rubric exists, not applied</td></tr><tr><td>One-shot vs conversational design</td><td>Don&#39;t mix paradigms</td><td>Medium</td><td>Partial</td></tr></tbody></table><h3 id="chapter-3-model" tabindex="-1">Chapter 3: Model <a class="header-anchor" href="#chapter-3-model" aria-label="Permalink to &quot;Chapter 3: Model&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Model selection by task type</td><td>Match model capability to task requirements</td><td>Medium</td><td>Not considered (single model)</td></tr><tr><td>Multi-model architectures</td><td>Use cheaper models for simple tasks, expensive for complex</td><td>Low</td><td>Not applicable in Cursor</td></tr><tr><td>Model evaluation for agents</td><td>Benchmarks and LLM-as-judge calibration</td><td>Low</td><td>Not needed yet</td></tr></tbody></table><h3 id="chapter-4-context" tabindex="-1">Chapter 4: Context <a class="header-anchor" href="#chapter-4-context" aria-label="Permalink to &quot;Chapter 4: Context&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Context as working memory</td><td>Quality over quantity in context window</td><td>High</td><td>Not considered</td></tr><tr><td>One agent, one task</td><td>Each agent does one focused job</td><td>High</td><td><strong>Strong</strong></td></tr><tr><td>Capability-capacity model</td><td>Context fill = capability drain</td><td>High</td><td>Not monitored</td></tr><tr><td>Frequent intentional compaction</td><td>Proactive cleanup at 40–60% capacity</td><td>Medium</td><td>Not applicable (manual workflow)</td></tr><tr><td>Progressive disclosure</td><td>Metadata → content → resources (3-layer)</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Multi-agent context isolation</td><td>Subagents return summaries, not raw data</td><td>High</td><td><strong>Not present</strong></td></tr><tr><td>Orchestrator context hygiene</td><td>Keep coordinator context clean</td><td>High</td><td><strong>Not present</strong></td></tr></tbody></table><p><strong>Key insight:</strong> The book demonstrates that context fill explains 80% of performance variance in multi-agent systems. The reconciliation agent, which runs last in the chain, is working with the most polluted context — the exact opposite of what the book recommends.</p><h3 id="chapter-5-tool-use" tabindex="-1">Chapter 5: Tool Use <a class="header-anchor" href="#chapter-5-tool-use" aria-label="Permalink to &quot;Chapter 5: Tool Use&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Skills as meta-tools</td><td>Temporary behavioural modifications, not actions</td><td>High</td><td>Already using</td></tr><tr><td>Progressive disclosure for skills</td><td>Discovery → activation → resource layers</td><td>High</td><td>Partial</td></tr><tr><td>Context contracts</td><td>Declarative input/output schemas for agents</td><td>Medium</td><td><strong>Not present</strong></td></tr><tr><td>Shared communications database</td><td>CRUD on shared state for coordination</td><td>Low</td><td>Not needed yet</td></tr></tbody></table><h3 id="chapter-6-patterns" tabindex="-1">Chapter 6: Patterns <a class="header-anchor" href="#chapter-6-patterns" aria-label="Permalink to &quot;Chapter 6: Patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Plan-Build-Review</td><td>Separate thinking from doing, review catches errors</td><td>High</td><td><strong>Not used</strong></td></tr><tr><td>Orchestrator pattern</td><td>Hub-and-spoke with parallel execution</td><td>High</td><td>Partial (sequential)</td></tr><tr><td>Expert Swarm</td><td>Domain expert + parallel workers + expertise inheritance</td><td>Medium</td><td>Not applicable yet</td></tr><tr><td>Human-in-the-Loop</td><td>Explicit approval gates between phases</td><td>High</td><td>Implicit only</td></tr><tr><td>Progressive Disclosure pattern</td><td>Load context on demand for large knowledge bases</td><td>Medium</td><td><strong>Not present</strong></td></tr><tr><td>Self-Improving Experts</td><td>Commands that learn from production experience</td><td>Medium</td><td><strong>Not present</strong></td></tr><tr><td>Dependency-aware batching</td><td>Parallelise independent steps, serialise dependent</td><td>High</td><td>Not used</td></tr><tr><td>Single-message parallelism</td><td>Invoke all independent agents in one message</td><td>High</td><td><strong>Not used</strong></td></tr><tr><td>Spec file as shared context</td><td>Single artifact flows through all phases</td><td>High</td><td>Partial (intake template)</td></tr><tr><td>Council pattern</td><td>Read-only parallel experts for analysis</td><td>High</td><td><strong>Matches workflow</strong></td></tr></tbody></table><p><strong>Key insight:</strong> The book&#39;s Pattern Selection Decision Tree recommends starting with Plan-Build-Review as the default. The existing workflow skips the Plan and Review phases entirely, running all agents in &quot;Build&quot; mode.</p><h3 id="chapter-7-practices" tabindex="-1">Chapter 7: Practices <a class="header-anchor" href="#chapter-7-practices" aria-label="Permalink to &quot;Chapter 7: Practices&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>High-leverage review</td><td>Review research and plans, not code line-by-line</td><td>High</td><td>Implicit</td></tr><tr><td>Eval-driven development</td><td>Write eval cases before writing prompts</td><td>High</td><td><strong>Not applied</strong></td></tr><tr><td>Evaluation spectrum</td><td>Vibes → scripted → automated → production</td><td>High</td><td>Currently at &quot;vibes&quot;</td></tr><tr><td>Building eval sets from failures</td><td>Capture production failures as test cases</td><td>Medium</td><td><strong>Not present</strong></td></tr><tr><td>Three-tier evaluation</td><td>Smoke (3–10) / Core (20–50) / Full (100+)</td><td>Medium</td><td>Not implemented</td></tr><tr><td>Agent debugging methodology</td><td>Classify → Isolate → Verbose → Simplify → Contrast</td><td>High</td><td>Not documented</td></tr><tr><td>Cost-per-success metric</td><td>Token usage / successful completions</td><td>Medium</td><td>Not tracked</td></tr></tbody></table><p><strong>Key insight:</strong> &quot;Without measurement, development becomes guesswork. Evaluation separates engineering from tinkering.&quot; The book argues that even 3–5 well-chosen eval cases beat 50 random examples.</p><h3 id="chapter-8-mental-models" tabindex="-1">Chapter 8: Mental Models <a class="header-anchor" href="#chapter-8-mental-models" aria-label="Permalink to &quot;Chapter 8: Mental Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Prompt Maturity Model (7 levels)</td><td>Static → Parameterised → Conditional → Contextual → Higher-Order → Self-Modifying → Meta-Cognitive</td><td>High</td><td>Skills at Level 4</td></tr><tr><td>Specs as Source Code</td><td>Specs are the primary programming surface; generated output is secondary</td><td>High</td><td>Partial</td></tr><tr><td>Context as Code</td><td>Treat agent knowledge like software, not documents</td><td>Medium</td><td>Not applied</td></tr><tr><td>Design as Bottleneck</td><td>When implementation is automated, design is the constraint</td><td>High</td><td>Aligns with research focus</td></tr></tbody></table><h3 id="chapter-9-practitioner-toolkit" tabindex="-1">Chapter 9: Practitioner Toolkit <a class="header-anchor" href="#chapter-9-practitioner-toolkit" aria-label="Permalink to &quot;Chapter 9: Practitioner Toolkit&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technique</th><th>Description</th><th>Relevance</th><th>Status</th></tr></thead><tbody><tr><td>Claude Code skills system</td><td>Progressive disclosure with SKILL.md files</td><td>High</td><td>Already using (Cursor variant)</td></tr><tr><td>IDE integration patterns</td><td>Cursor-specific skill and rule patterns</td><td>High</td><td>Already using</td></tr></tbody></table><h3 id="summary-statistics" tabindex="-1">Summary statistics <a class="header-anchor" href="#summary-statistics" aria-label="Permalink to &quot;Summary statistics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Count</th></tr></thead><tbody><tr><td><strong>Strong / Already using</strong></td><td>8</td></tr><tr><td><strong>Partial</strong></td><td>10</td></tr><tr><td><strong>Not present / Not applied</strong></td><td>20</td></tr><tr><td><strong>Not applicable / Low relevance</strong></td><td>7</td></tr></tbody></table>',27)])])}const m=e(i,[["render",n]]);export{g as __pageData,m as default};
